 1→/**
 2→ * Agent 類型
 3→ */
 4→export type AgentType = 'codex' | 'claude' | 'gemini';
 5→
 6→/**
 7→ * CLI 選項
 8→ */
 9→export interface CliOptions {
10→  agentType: AgentType;
11→  raw: boolean;
12→  project?: string;
13→  follow: boolean;
14→  verbose: boolean;
15→  /** Suppress non-error output messages */
16→  quiet: boolean;
17→  /** File polling interval in milliseconds (default: 500) */
18→  sleepInterval: number;
19→  /** Number of initial lines to show per file (default: all) */
20→  lines?: number;
21→  /** Claude/Codex: tail subagent log (true = latest, string = specific ID) */
22→  subagent?: string | true;
23→  /** Claude/Codex: interactive mode for switching between main session and subagents (Codex: Phase 3) */
24→  interactive: boolean;
25→  /** Claude/Codex: include subagent content in output (non-interactive mode) */
26→  withSubagents: boolean;
27→  /** Auto-switch to latest main session in project */
28→  autoSwitch: boolean;
29→  /** Claude/Codex: auto-open tmux pane for each new subagent (Codex: Phase 2) */
30→  pane: boolean;
31→  /** Optional session ID to load (partial match supported) */
32→  sessionId?: string;
33→}
34→
35→/**
36→ * Parser 設定選項
37→ */
38→export interface ParserOptions {
39→  verbose: boolean;
40→}
41→
42→/**
43→ * Session 檔案資訊
44→ */
45→export interface SessionFile {
46→  path: string;
47→  mtime: Date;
48→  agentType: AgentType;
49→}
50→
51→/**
52→ * 專案資訊（用於 auto-switch）
53→ */
54→export interface ProjectInfo {
55→  /** 專案目錄路徑（用於 session 搜尋範圍） */
56→  projectDir: string;
57→  /** 顯示名稱（用於日誌輸出） */
58→  displayName?: string;
59→}
60→
61→/**
62→ * Claude Session 查找結果（支援 subagent 關聯）
63→ * 當指定 subagent ID 時，會同時返回主 session 和 subagent
64→ */
65→export interface ClaudeSessionResult {
66→  main: SessionFile;
67→  subagent?: SessionFile;
68→}
69→
70→/**
71→ * JSONL 解析結果
72→ */
73→export interface ParsedLine {
74→  type: string;
75→  timestamp: string;
76→  raw: unknown;
77→  formatted: string;
78→  /** Tool 名稱（僅 function_call 類型使用，用於顏色判斷） */
79→  toolName?: string;
80→  /** 來源標籤（多檔案監控時用於區分來源，如 "[MAIN]" 或 "[a0627b6]"） */
81→  sourceLabel?: string;
82→  /** 是否為 Task (or Agent) tool_use（用於早期 Subagent 偵測） */
83→  isTaskToolUse?: boolean;
84→  /** Task (or Agent) tool_use 的 description 欄位（用於 pane 命名） */
85→  taskDescription?: string;
86→}
