  1→import { stat } from 'node:fs/promises';
  2→import { homedir } from 'node:os';
  3→import { join } from 'node:path';
  4→import { Glob } from 'bun';
  5→import type { Agent, LineParser, SessionFinder } from '../agent.interface.ts';
  6→import type {
  7→  ClaudeSessionResult,
  8→  ParsedLine,
  9→  ParserOptions,
 10→  SessionFile,
 11→} from '../../core/types.ts';
 12→import {
 13→  contentToString,
 14→  formatMultiline,
 15→  truncateByLines,
 16→} from '../../utils/text.ts';
 17→import { formatToolUse, isSubagentTool } from '../../utils/format-tool.ts';
 18→
 19→/**
 20→ * Claude Code Session Finder
 21→ * 目錄結構: ~/.claude/projects/{encoded-path}/{UUID}.jsonl
 22→ */
 23→class ClaudeSessionFinder implements SessionFinder {
 24→  private baseDir: string;
 25→
 26→  constructor() {
 27→    this.baseDir = join(homedir(), '.claude', 'projects');
 28→  }
 29→
 30→  getBaseDir(): string {
 31→    return this.baseDir;
 32→  }
 33→
 34→  async findLatest(options: { project?: string }): Promise<SessionFile | null> {
 35→    const glob = new Glob('**/*.jsonl');
 36→    const files: { path: string; mtime: Date }[] = [];
 37→
 38→    for await (const file of glob.scan({ cwd: this.baseDir, absolute: true })) {
 39→      const filename = file.split('/').pop() || '';
 40→
 41→      // 排除 agent-* 開頭的檔案
 42→      if (filename.startsWith('agent-')) continue;
 43→
 44→      // 只匹配 UUID 格式的檔案名
 45→      const uuidPattern =
 46→        /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}\.jsonl$/i;
 47→      if (!uuidPattern.test(filename)) continue;
 48→
 49→      // 如果有 project filter，做模糊比對
 50→      if (options.project) {
 51→        const pattern = options.project.toLowerCase();
 52→        // 對路徑做模糊比對（包含專案目錄名稱）
 53→        if (!file.toLowerCase().includes(pattern)) continue;
 54→      }
 55→
 56→      try {
 57→        const stats = await stat(file);
 58→        files.push({ path: file, mtime: stats.mtime });
 59→      } catch {
 60→        // 忽略無法讀取的檔案
 61→      }
 62→    }
 63→
 64→    if (files.length === 0) return null;
 65→
 66→    // 按修改時間排序，取最新的
 67→    files.sort((a, b) => b.mtime.getTime() - a.mtime.getTime());
 68→
 69→    const latest = files[0];
 70→    if (!latest) return null;
 71→
 72→    return {
 73→      path: latest.path,
 74→      mtime: latest.mtime,
 75→      agentType: 'claude',
 76→    };
 77→  }
 78→
 79→  /**
 80→   * 找到 subagent 檔案
 81→   * 新結構: {sessionId}/subagents/agent-{7位hex}.jsonl
 82→   * @param options.subagentId - 指定的 subagent ID，不提供則找最新的
 83→   */
 84→  async findSubagent(options: {
 85→    project?: string;
 86→    subagentId?: string;
 87→  }): Promise<SessionFile | null> {
 88→    const { project, subagentId } = options;
 89→
 90→    // 決定 glob pattern（新結構：{UUID}/subagents/ 目錄下）
 91→    const pattern = subagentId
 92→      ? `**/*/subagents/agent-${subagentId}.jsonl`
 93→      : '**/*/subagents/agent-*.jsonl';
 94→
 95→    const glob = new Glob(pattern);
 96→    const files: { path: string; mtime: Date }[] = [];
 97→
 98→    for await (const file of glob.scan({ cwd: this.baseDir, absolute: true })) {
 99→      const filename = file.split('/').pop() || '';
100→
101→      // 驗證 subagent 檔名格式: agent-{7~40位十六進制}.jsonl
102→      const subagentPattern = /^agent-[0-9a-f]{7,40}\.jsonl$/i;
103→      if (!subagentPattern.test(filename)) continue;
104→
105→      // project filter
106→      if (project && !file.toLowerCase().includes(project.toLowerCase())) {
107→        continue;
108→      }
109→
110→      try {
111→        const stats = await stat(file);
112→        files.push({ path: file, mtime: stats.mtime });
113→      } catch {
114→        // 忽略無法讀取的檔案
115→      }
116→    }
117→
118→    if (files.length === 0) return null;
119→
120→    // 按修改時間排序，取最新的
121→    files.sort((a, b) => b.mtime.getTime() - a.mtime.getTime());
122→    const latest = files[0];
123→    if (!latest) return null;
124→
125→    return {
126→      path: latest.path,
127→      mtime: latest.mtime,
128→      agentType: 'claude',
129→    };
130→  }
131→
132→  /**
133→   * 依 session ID 查找 session 檔案
134→   * 支援主 session（UUID）和 subagent（7位hex）
135→   * 當指定 subagent ID 時，會同時返回主 session 和 subagent
136→   */
137→  async findBySessionId(
138→    sessionId: string,
139→    options: { project?: string }
140→  ): Promise<SessionFile | ClaudeSessionResult | null> {
141→    const idType = this.detectIdType(sessionId);
142→
143→    // 如果是主 session UUID 或未知類型，先嘗試找主 session
144→    if (idType === 'main' || idType === 'unknown') {
145→      const mainResult = await this.findMainBySessionId(sessionId, options);
146→      if (mainResult) return mainResult;
147→    }
148→
149→    // 如果是 subagent ID 或未知類型（且主 session 沒找到），嘗試找 subagent
150→    if (idType === 'subagent' || idType === 'unknown') {
151→      const subagentResult = await this.findSubagentBySessionId(
152→        sessionId,
153→        options
154→      );
155→      if (subagentResult) {
156→        // 反推主 session
157→        const mainPath = this.getMainSessionFromSubagent(subagentResult.path);
158→        if (mainPath) {
159→          try {
160→            const mainStats = await stat(mainPath);
161→            return {
162→              main: {
163→                path: mainPath,
164→                mtime: mainStats.mtime,
165→                agentType: 'claude',
166→              },
167→              subagent: subagentResult,
168→            };
169→          } catch {
170→            // 主 session 不存在，只返回 subagent
171→            return subagentResult;
172→          }
173→        }
174→        return subagentResult;
175→      }
176→    }
177→
178→    return null;
179→  }
180→
181→  /**
182→   * 判斷 ID 類型
183→   */
184→  private detectIdType(id: string): 'main' | 'subagent' | 'unknown' {
185→    // 完整 UUID 格式
186→    const uuidPattern =
187→      /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
188→    // Subagent 格式：agent-{7hex} 或純 {7hex}
189→    const subagentPattern = /^(agent-)?[0-9a-f]{7}$/i;
190→
191→    if (uuidPattern.test(id)) return 'main';
192→    if (subagentPattern.test(id)) return 'subagent';
193→
194→    // 如果是 UUID 前綴（8位以上但不完整），視為主 session
195→    if (/^[0-9a-f]{8,35}$/i.test(id)) return 'main';
196→
197→    return 'unknown';
198→  }
199→
200→  /**
201→   * 從 subagent 路徑反推主 session 路徑
202→   * 路徑結構: {projectDir}/{sessionUUID}/subagents/agent-xxx.jsonl
203→   */
204→  private getMainSessionFromSubagent(subagentPath: string): string | null {
205→    const parts = subagentPath.split('/');
206→    const subagentsIdx = parts.lastIndexOf('subagents');
207→
208→    if (subagentsIdx === -1 || subagentsIdx < 2) return null;
209→
210→    const sessionUUID = parts[subagentsIdx - 1];
211→    const projectDir = parts.slice(0, subagentsIdx - 1).join('/');
212→
213→    // 主 session 在 projectDir 下，檔名為 sessionUUID.jsonl
214→    return join(projectDir, `${sessionUUID}.jsonl`);
215→  }
216→
217→  /**
218→   * 依 session ID 查找主 session
219→   */
220→  private async findMainBySessionId(
221→    sessionId: string,
222→    options: { project?: string }
223→  ): Promise<SessionFile | null> {
224→    const glob = new Glob('**/*.jsonl');
225→    const candidates: { path: string; mtime: Date; priority: number }[] = [];
226→
227→    const uuidPattern =
228→      /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}\.jsonl$/i;
229→    const searchTerm = sessionId.toLowerCase();
230→
231→    for await (const file of glob.scan({ cwd: this.baseDir, absolute: true })) {
232→      const filename = file.split('/').pop() || '';
233→
234→      // 排除 subagent 檔案
235→      if (filename.startsWith('agent-')) continue;
236→
237→      // 只匹配 UUID 格式的檔案名
238→      if (!uuidPattern.test(filename)) continue;
239→
240→      // project filter
241→      if (options.project) {
242→        const pattern = options.project.toLowerCase();
243→        if (!file.toLowerCase().includes(pattern)) continue;
244→      }
245→
246→      const baseName = filename.replace(/\.jsonl$/, '').toLowerCase();
247→
248→      // 計算匹配優先級
249→      let priority = 0;
250→      if (baseName === searchTerm) {
251→        priority = 3; // 精確匹配
252→      } else if (baseName.startsWith(searchTerm)) {
253→        priority = 2; // 前綴匹配
254→      } else if (baseName.includes(searchTerm)) {
255→        priority = 1; // 包含匹配
256→      }
257→
258→      if (priority === 0) continue;
259→
260→      try {
261→        const stats = await stat(file);
262→        candidates.push({ path: file, mtime: stats.mtime, priority });
263→      } catch {
264→        // 忽略
265→      }
266→    }
267→
268→    if (candidates.length === 0) return null;
269→
270→    // 排序：優先級降序 > mtime 降序
271→    candidates.sort((a, b) => {
272→      if (b.priority !== a.priority) return b.priority - a.priority;
273→      return b.mtime.getTime() - a.mtime.getTime();
274→    });
275→
276→    const best = candidates[0];
277→    if (!best) return null;
278→
279→    return {
280→      path: best.path,
281→      mtime: best.mtime,
282→      agentType: 'claude',
283→    };
284→  }
285→
286→  /**
287→   * 依 session ID 查找 subagent
288→   */
289→  private async findSubagentBySessionId(
290→    sessionId: string,
291→    options: { project?: string }
292→  ): Promise<SessionFile | null> {
293→    // 正規化：移除 agent- 前綴
294→    const normalizedId = sessionId.replace(/^agent-/i, '').toLowerCase();
295→
296→    const glob = new Glob('**/*/subagents/agent-*.jsonl');
297→    const candidates: { path: string; mtime: Date; priority: number }[] = [];
298→
299→    const subagentPattern = /^agent-([0-9a-f]{7,40})\.jsonl$/i;
300→
301→    for await (const file of glob.scan({ cwd: this.baseDir, absolute: true })) {
302→      const filename = file.split('/').pop() || '';
303→      const match = filename.match(subagentPattern);
304→
305→      if (!match) continue;
306→
307→      const subagentId = (match[1] || '').toLowerCase();
308→
309→      // project filter
310→      if (options.project) {
311→        const pattern = options.project.toLowerCase();
312→        if (!file.toLowerCase().includes(pattern)) continue;
313→      }
314→
315→      // 計算匹配優先級
316→      let priority = 0;
317→      if (subagentId === normalizedId) {
318→        priority = 3; // 精確匹配
319→      } else if (subagentId.startsWith(normalizedId)) {
320→        priority = 2; // 前綴匹配
321→      } else if (subagentId.includes(normalizedId)) {
322→        priority = 1; // 包含匹配
323→      }
324→
325→      if (priority === 0) continue;
326→
327→      try {
328→        const stats = await stat(file);
329→        candidates.push({ path: file, mtime: stats.mtime, priority });
330→      } catch {
331→        // 忽略
332→      }
333→    }
334→
335→    if (candidates.length === 0) return null;
336→
337→    // 排序：優先級降序 > mtime 降序
338→    candidates.sort((a, b) => {
339→      if (b.priority !== a.priority) return b.priority - a.priority;
340→      return b.mtime.getTime() - a.mtime.getTime();
341→    });
342→
343→    const best = candidates[0];
344→    if (!best) return null;
345→
346→    return {
347→      path: best.path,
348→      mtime: best.mtime,
349→      agentType: 'claude',
350→    };
351→  }
352→}
