354→/**
355→ * Claude Code JSONL 解析器
356→ */
357→class ClaudeLineParser implements LineParser {
358→  private verbose: boolean;
359→  /** 追蹤 assistant message 內部的處理進度 */
360→  private currentMessageState: {
361→    data: Record<string, unknown>;
362→    contentParts: Array<{
363→      type: string;
364→      text?: string;
365→      name?: string;
366→      input?: Record<string, unknown>;
367→    }>;
368→    partIndex: number;
369→    modelShort: string;
370→    hasTextBefore: boolean;
371→  } | null = null;
372→  /** 追蹤已處理的 line，避免 while 迴圈重複處理 */
373→  private lastProcessedLine: string | null = null;
374→
375→  constructor(options: ParserOptions = { verbose: false }) {
376→    this.verbose = options.verbose;
377→  }
378→
379→  parse(line: string): ParsedLine | null {
380→    // 如果正在處理 assistant message 的內部狀態
381→    if (this.currentMessageState) {
382→      const result = this.processAssistantPart();
383→      if (result) return result;
384→      // 處理完畢，清除狀態並回傳 null
385→      this.currentMessageState = null;
386→      return null;
387→    }
388→
389→    if (!line.trim()) return null;
390→
391→    // 避免重複處理同一個 line（非 assistant message 不需要 while 迴圈）
392→    if (line === this.lastProcessedLine) {
393→      return null;
394→    }
395→    this.lastProcessedLine = line;
396→
397→    try {
398→      const data = JSON.parse(line);
399→      const type = data.type || 'unknown';
400→      const timestamp = data.timestamp || '';
401→
402→      // assistant message 需要特殊處理（可能包含多個 tool_use）
403→      if (type === 'assistant') {
404→        return this.parseAssistantMessage(data, timestamp);
405→      }
406→
407→      // toolUseResult 記錄（subagent 完成時的回傳）
408→      if (data.toolUseResult) {
409→        return this.parseToolUseResult(data, timestamp);
410→      }
411→
412→      const formatted = this.format(data);
413→
414→      // 空內容不輸出
415→      if (!formatted) return null;
416→
417→      return {
418→        type,
419→        timestamp,
420→        raw: data,
421→        formatted,
422→      };
423→    } catch {
424→      return null;
425→    }
426→  }
427→
428→  /**
429→   * 解析 assistant message，拆分成多個部分
430→   */
431→  private parseAssistantMessage(
432→    data: Record<string, unknown>,
433→    _timestamp: string
434→  ): ParsedLine | null {
435→    const message = data.message as {
436→      model?: string;
437→      content: Array<{
438→        type: string;
439→        text?: string;
440→        name?: string;
441→        input?: Record<string, unknown>;
442→      }>;
443→    };
444→    const model = message?.model || '';
445→    const content = message?.content || [];
446→
447→    // 簡化 model 顯示
448→    const modelShort = model
449→      .replace('claude-', '')
450→      .replace('-20251101', '')
451→      .replace('-', ' ');
452→
453→    // 過濾有效的部分（text 或 tool_use）
454→    const validParts = content.filter(
455→      (part) =>
456→        (part.type === 'text' && part.text?.trim()) ||
457→        (part.type === 'tool_use' && part.name)
458→    );
459→
460→    if (validParts.length === 0) return null;
461→
462→    // 初始化狀態
463→    this.currentMessageState = {
464→      data,
465→      contentParts: validParts,
466→      partIndex: 0,
467→      modelShort,
468→      hasTextBefore: false,
469→    };
470→
471→    return this.processAssistantPart();
472→  }
473→
474→  /**
475→   * 處理 assistant message 的下一個部分
476→   */
477→  private processAssistantPart(): ParsedLine | null {
478→    if (!this.currentMessageState) return null;
479→
480→    const { data, contentParts, partIndex, modelShort, hasTextBefore } =
481→      this.currentMessageState;
482→    if (partIndex >= contentParts.length) return null;
483→
484→    const part = contentParts[partIndex];
485→    if (!part) return null;
486→
487→    this.currentMessageState.partIndex++;
488→    const timestamp = (data as { timestamp?: string }).timestamp || '';
489→
490→    if (part.type === 'text' && part.text) {
491→      this.currentMessageState.hasTextBefore = true;
492→      const preview = truncateByLines(part.text, { verbose: this.verbose });
493→      const modelInfo = modelShort && !hasTextBefore ? `(${modelShort})` : '';
494→      return {
495→        type: 'assistant',
496→        timestamp,
497→        raw: data,
498→        formatted: `${modelInfo}${formatMultiline(preview)}`,
499→      };
500→    }
501→
502→    if (part.type === 'tool_use' && part.name) {
503→      const isTask = isSubagentTool(part.name);
504→      const taskDescription =
505→        isTask && typeof part.input?.description === 'string'
506→          ? part.input.description
507→          : undefined;
508→
509→      return {
510→        type: 'function_call',
511→        timestamp,
512→        raw: part,
513→        formatted: formatToolUse(part.name, part.input, {
514→          verbose: this.verbose,
515→        }),
516→        toolName: part.name,
517→        isTaskToolUse: isTask,
518→        taskDescription,
519→      };
520→    }
521→
522→    return null;
523→  }
524→
525→  /**
526→   * 解析 toolUseResult 記錄（subagent 完成時的回傳）
527→   */
528→  private parseToolUseResult(
529→    data: Record<string, unknown>,
530→    timestamp: string
531→  ): ParsedLine | null {
532→    const toolUseResult = data.toolUseResult as {
533→      status?: string;
534→      agentId?: string;
535→      prompt?: string;
536→      totalDurationMs?: number;
537→      totalTokens?: number;
538→      totalToolUseCount?: number;
539→    };
540→
541→    if (!toolUseResult) return null;
542→
543→    const { status, agentId, totalDurationMs, totalTokens, totalToolUseCount } =
544→      toolUseResult;
545→
546→    // 格式化輸出
547→    const parts: string[] = [];
548→    if (status) parts.push(status);
549→    if (agentId) parts.push(`agent:${agentId}`);
550→    if (totalDurationMs) parts.push(`${(totalDurationMs / 1000).toFixed(1)}s`);
551→    if (totalTokens) parts.push(`${totalTokens} tokens`);
552→    if (totalToolUseCount) parts.push(`${totalToolUseCount} tools`);
553→
554→    const formatted = parts.length > 0 ? `(${parts.join(', ')})` : '';
555→
556→    return {
557→      type: 'tool_result',
558→      timestamp,
559→      raw: data,
560→      formatted,
561→    };
562→  }
563→
564→  private format(data: Record<string, unknown>): string {
565→    const type = data.type as string;
566→
567→    switch (type) {
568→      case 'file-history-snapshot': {
569→        return ''; // 不顯示 snapshot
570→      }
571→
572→      case 'user': {
573→        const message = data.message as { content: unknown };
574→        const content = contentToString(message?.content);
575→        const preview = truncateByLines(content, { verbose: this.verbose });
576→        return formatMultiline(preview);
577→      }
578→
579→      // assistant 由 parseAssistantMessage 處理
580→
581→      default:
582→        return '';
583→    }
584→  }
585→}
