 70→async function main(): Promise<void> {
 71→  const options = parseArgs(process.argv);
 72→
 73→  // 選擇 Agent
 74→  const agent: Agent =
 75→    options.agentType === 'codex'
 76→      ? new CodexAgent({ verbose: options.verbose })
 77→      : options.agentType === 'gemini'
 78→        ? new GeminiAgent({ verbose: options.verbose })
 79→        : new ClaudeAgent({ verbose: options.verbose });
 80→
 81→  // 選擇 Formatter
 82→  const formatter: Formatter = options.raw
 83→    ? new RawFormatter()
 84→    : new PrettyFormatter();
 85→
 86→  // 找到目標 session 檔案
 87→  let sessionFile: SessionFile | null = null;
 88→  let subagentFile: SessionFile | null = null; // Claude subagent 關聯
 89→
 90→  // 判斷搜尋模式
 91→  if (options.sessionId) {
 92→    // 使用 sessionId 搜尋特定 session
 93→    log(
 94→      options.quiet,
 95→      chalk.gray(
 96→        `Searching for ${options.agentType} session "${options.sessionId}"...`
 97→      )
 98→    );
 99→
100→    const finder = agent.finder;
101→    if (!finder.findBySessionId) {
102→      console.error(
103→        chalk.red(
104→          `Session ID lookup not supported for ${options.agentType} agent`
105→        )
106→      );
107→      process.exit(1);
108→    }
109→
110→    const result = await finder.findBySessionId(options.sessionId, {
111→      project: options.project,
112→    });
113→
114→    if (!result) {
115→      const projectInfo = options.project
116→        ? ` in project "${options.project}"`
117→        : '';
118→      console.error(
119→        chalk.red(
120→          `No session found matching "${options.sessionId}"${projectInfo}`
121→        )
122→      );
123→      process.exit(1);
124→    }
125→
126→    // 判斷是否為 ClaudeSessionResult（有 main 和 subagent）
127→    if ('main' in result && 'subagent' in result) {
128→      const claudeResult = result as ClaudeSessionResult;
129→      sessionFile = claudeResult.main;
130→      subagentFile = claudeResult.subagent || null;
131→      log(
132→        options.quiet,
133→        chalk.green(`Found main session: ${sessionFile.path}`)
134→      );
135→      if (subagentFile) {
136→        log(options.quiet, chalk.green(`Found subagent: ${subagentFile.path}`));
137→      }
138→    } else {
139→      sessionFile = result as SessionFile;
140→      log(options.quiet, chalk.green(`Found: ${sessionFile.path}`));
141→    }
142→    log(
143→      options.quiet,
144→      chalk.gray(`Modified: ${sessionFile.mtime.toLocaleString()}`)
145→    );
146→  } else if (
147→    (options.agentType === 'claude' || options.agentType === 'codex') &&
148→    options.subagent !== undefined
149→  ) {
150→    // Claude/Codex subagent 模式（使用 --subagent 選項）
151→    log(
152→      options.quiet,
153→      chalk.gray(`Searching for latest ${options.agentType} subagent...`)
154→    );
155→
156→    const finder = agent.finder;
157→    if (finder.findSubagent) {
158→      const subagentId =
159→        typeof options.subagent === 'string' ? options.subagent : undefined;
160→
161→      sessionFile = await finder.findSubagent({
162→        project: options.project,
163→        subagentId,
164→      });
165→
166→      if (!sessionFile) {
167→        const idInfo = subagentId ? ` (id: ${subagentId})` : '';
168→        const projectInfo = options.project
169→          ? ` in project "${options.project}"`
170→          : '';
171→        console.error(
172→          chalk.red(`No subagent file found${idInfo}${projectInfo}`)
173→        );
174→        process.exit(1);
175→      }
176→    }
177→    log(options.quiet, chalk.green(`Found: ${sessionFile?.path}`));
178→    log(
179→      options.quiet,
180→      chalk.gray(`Modified: ${sessionFile?.mtime.toLocaleString()}`)
181→    );
182→  } else {
183→    // 預設模式：找最新的 session
184→    log(
185→      options.quiet,
186→      chalk.gray(`Searching for latest ${options.agentType} session...`)
187→    );
188→
189→    sessionFile = await agent.finder.findLatest({
190→      project: options.project,
191→    });
192→
193→    if (!sessionFile) {
194→      console.error(
195→        chalk.red(
196→          `No session file found for ${options.agentType}${options.project ? ` (project: ${options.project})` : ''}`
197→        )
198→      );
199→      process.exit(1);
200→    }

200→    }
201→
202→    log(options.quiet, chalk.green(`Found: ${sessionFile.path}`));
203→    log(
204→      options.quiet,
205→      chalk.gray(`Modified: ${sessionFile.mtime.toLocaleString()}`)
206→    );
207→  }
208→
209→  if (!sessionFile) {
210→    console.error(chalk.red('No session file found'));
211→    process.exit(1);
212→  }
213→
214→  // 監控模式判斷：
215→  // 1. Claude 主 session 模式 → Claude 多檔案監控
216→  // 2. Codex 主 session + withSubagents/pane → Codex 多檔案監控
217→  // 3. --subagent 選項 → 單檔案監控（Claude/Codex）
218→  // 4. 其他 agent → 單檔案監控
219→  if (options.agentType === 'claude' && options.subagent === undefined) {
220→    if (options.interactive) {
221→      // Interactive 模式：使用 SessionManager 管理輸出切換
222→      await startClaudeInteractiveWatch(
223→        sessionFile,
224→        formatter,
225→        options,
226→        subagentFile
227→      );
228→    } else {
229→      // 普通模式：所有來源輸出到 console
230→      await startClaudeMultiWatch(
231→        sessionFile,
232→        formatter,
233→        options,
234→        subagentFile
235→      );
236→    }
237→  } else if (options.agentType === 'codex' && options.interactive) {
238→    // Codex 互動模式（Phase 3）
239→    await startCodexInteractiveWatch(sessionFile, formatter, options);
240→  } else if (
241→    options.agentType === 'codex' &&
242→    options.subagent === undefined &&
243→    (options.withSubagents || options.pane)
244→  ) {
245→    // Codex 多檔案監控（主 session + subagents）
246→    await startCodexMultiWatch(sessionFile, formatter, options);
247→  } else {
248→    // 其他 agent 或 Claude/Codex subagent 模式：單檔案監控
249→    await startSingleWatch(agent, sessionFile, formatter, options);
250→  }
251→}
