253→/**
254→ * Claude 多檔案監控（主 session + subagents）
255→ * @param initialSubagent - 從 sessionId 參數指定的 subagent（可選）
256→ */
257→async function startClaudeMultiWatch(
258→  sessionFile: SessionFile,
259→  formatter: Formatter,
260→  options: CliOptions,
261→  initialSubagent: SessionFile | null = null
262→): Promise<void> {
263→  const projectDir = dirname(sessionFile.path);
264→  let subagentsDir = getSubagentsDir(sessionFile.path);
265→
266→  // 建立監控檔案列表（主 session）
267→  const files: WatchedFile[] = [{ path: sessionFile.path, label: MAIN_LABEL }];
268→
269→  // 只有在 withSubagents 為 true 時才掃描 subagent
270→  const existingAgentIds = new Set<string>();
271→  if (options.withSubagents) {
272→    // 掃描現有的 subagent（優先使用目錄掃描，確保找到所有檔案）
273→    const dirAgentIds = await scanForNewSubagents(subagentsDir, new Set());
274→    for (const id of dirAgentIds) {
275→      existingAgentIds.add(id);
276→    }
277→
278→    // 如果有從 sessionId 指定的 subagent，確保它被加入
279→    if (initialSubagent) {
280→      const initialAgentId = basename(initialSubagent.path, '.jsonl').replace(
281→        /^agent-/,
282→        ''
283→      );
284→      existingAgentIds.add(initialAgentId);
285→    }
286→
287→    const existingSubagentFiles = await buildSubagentFiles(
288→      subagentsDir,
289→      existingAgentIds
290→    );
291→    for (const { agentId, path } of existingSubagentFiles) {
292→      files.push({ path, label: makeAgentLabel(agentId) });
293→    }
294→
295→    if (existingAgentIds.size > 0) {
296→      log(
297→        options.quiet,
298→        chalk.gray(`Found ${existingAgentIds.size} subagent(s)`)
299→      );
300→    }
301→  }
302→  log(options.quiet, chalk.gray('---'));
303→
304→  // 為每個來源建立獨立的 parser
305→  let parsers = new Map<string, LineParser>();
306→  for (const file of files) {
307→    const parserAgent = new ClaudeAgent({ verbose: options.verbose });
308→    parsers.set(file.label, parserAgent.parser);
309→  }
310→
311→  // 非 follow 模式且有 subagent：收集所有行後按時間排序輸出
312→  if (!options.follow && options.withSubagents && files.length > 1) {
313→    await outputTimeSorted(files, parsers, formatter, options);
314→    process.exit(0);
315→  }
316→
317→  let multiWatcher = new MultiFileWatcher();
318→
319→  // 建立 PaneManager（--pane 模式時自動開啟 tmux pane）
320→  let paneManager: PaneManager | null = null;
321→  if (options.pane) {
322→    const controller = createTerminalController();
323→    if (controller.isAvailable()) {
324→      paneManager = new PaneManager(
325→        controller,
326→        (agentId, _subagentPath) => {
327→          // 使用當前執行方式重建指令（支援 bun run、npx、全域安裝等）
328→          // 用雙引號包覆路徑，防止空格造成 shell 指令斷裂
329→          const runtime = `"${process.argv[0]}"`;
330→          const script = `"${process.argv[1]}"`;
331→          return `${runtime} ${script} claude --subagent ${agentId} -q --no-pane`;
332→        },
333→        (msg) => log(options.quiet, chalk.gray(msg))
334→      );
335→    } else {
336→      log(
337→        options.quiet,
338→        chalk.yellow('Warning: tmux not detected, --pane disabled')
339→      );
340→    }
341→  }
342→
343→  // 提取 pane 相關回呼（消除 paneManager! 斷言，用 const 捕獲確認非 null 的參照）
344→  const pm = paneManager; // 閉包捕獲，不受外部重賦值影響
345→  const openPaneForSubagent = pm
346→    ? (agentId: string, subagentPath: string, description?: string) => {
347→        pm.openPane(agentId, subagentPath, description).catch((err) => {
348→          log(
349→            options.quiet,
350→            chalk.yellow(`[pane] Failed to open pane: ${err}`)
351→          );
352→        });
353→      }
354→    : undefined;
355→
356→  const onSubagentDone = pm
357→    ? (agentId: string) => {
358→        const subagentPath = buildSubagentPath(subagentsDir, agentId);
359→
360→        // 先讀取並輸出最後的 assistant 訊息，再關閉 pane
361→        (async () => {
362→          try {
363→            const parts = await readLastAssistantMessage(
364→              subagentPath,
365→              options.verbose
366→            );
367→            const label = makeAgentLabel(agentId);
368→            for (const part of parts) {
369→              part.sourceLabel = label;
370→              console.log(formatter.format(part));
371→            }
372→          } catch {
373→            // 讀取失敗不影響 pane 關閉
374→          } finally {
375→            await pm.closePaneByAgentId(agentId);
376→          }
377→        })().catch(() => {});
378→      }
379→    : undefined;
380→
381→  const hasPaneCallback = pm
382→    ? (agentId: string) => pm.hasPaneForAgent(agentId)
383→    : undefined;
384→
385→  // pane 模式下，進入時既有 subagent 加入 suppress set，避免歷史內容污染 main pane
386→  const suppressedForPane = pm ? new Set(existingAgentIds) : new Set<string>();
387→
388→  const shouldOutput = pm
389→    ? (label: string) => {
390→        if (label === MAIN_LABEL) return true;
391→        const agentId = extractAgentIdFromLabel(label);
392→        if (suppressedForPane.has(agentId)) return false;
393→        return !pm.hasPaneForAgent(agentId);
394→      }
395→    : undefined;
396→
397→  // 建立 SubagentDetector（整合 early detection 和 fallback detection）
398→  let detector = new SubagentDetector(existingAgentIds, {
399→    subagentsDir,
400→    output: new ConsoleOutputHandler(),
401→    watcher: { addFile: (f) => multiWatcher.addFile(f) },
402→    session: new NoOpSessionHandler(),
403→    enabled: options.follow && options.withSubagents,
404→    onNewSubagent: openPaneForSubagent,
405→    onSubagentEnter: openPaneForSubagent,
406→    onSubagentDone,
407→    hasPane: hasPaneCallback,
408→  });
409→  detector.startDirectoryWatch();
410→
411→  // ========== Non-Interactive Super-Follow ==========
412→  let currentSessionPath = sessionFile.path;
413→
414→  const switchToSession = async (
415→    nextSessionFile: SessionFile
416→  ): Promise<void> => {
417→    // 停止現有監控
418→    detector?.stop();
419→    multiWatcher.stop();
420→
421→    // 更新當前 session 路徑
422→    currentSessionPath = nextSessionFile.path;
423→
424→    // 重新初始化監控
425→    const newSessionId = basename(nextSessionFile.path, '.jsonl');
426→    const newSubagentsDir = getSubagentsDir(nextSessionFile.path);
427→
428→    const newFiles: WatchedFile[] = [
429→      { path: nextSessionFile.path, label: MAIN_LABEL },
430→    ];
431→    const newExistingAgentIds = new Set<string>();
432→
433→    // 掃描現有的 subagents
434→    if (options.withSubagents) {
435→      const dirAgentIds = await scanForNewSubagents(newSubagentsDir, new Set());
436→      for (const id of dirAgentIds) {
437→        newExistingAgentIds.add(id);
438→      }
439→
440→      const existingSubagentFiles = await buildSubagentFiles(
441→        newSubagentsDir,
442→        newExistingAgentIds
443→      );
444→      for (const { agentId, path } of existingSubagentFiles) {
445→        newFiles.push({ path, label: makeAgentLabel(agentId) });
446→      }
447→
448→      if (newExistingAgentIds.size > 0) {
449→        log(
450→          options.quiet,
451→          chalk.gray(`Found ${newExistingAgentIds.size} subagent(s)`)
452→        );
453→      }
454→    }
455→
456→    // 更新 suppress set：清空後填入新 session 的既有 subagent
457→    if (pm) {
458→      suppressedForPane.clear();
459→      for (const agentId of newExistingAgentIds) suppressedForPane.add(agentId);
460→    }
461→
462→    // 輸出切換訊息
463→    log(
464→      options.quiet,
465→      chalk.gray(`--- Switched to session ${newSessionId} ---`)
466→    );
467→    log(options.quiet, chalk.gray('---'));
468→
469→    // 重新建立 parsers
470→    const newParsers = new Map<string, LineParser>();
471→    for (const file of newFiles) {
472→      const parserAgent = new ClaudeAgent({ verbose: options.verbose });
473→      newParsers.set(file.label, parserAgent.parser);
474→    }
475→    parsers = newParsers;
476→
477→    // 重新建立 multiWatcher（先建立，但還不啟動）
478→    const newMultiWatcher = new MultiFileWatcher();
479→
480→    // 重新建立 detector（捕獲新的 multiWatcher，沿用 pane 回呼）
