483→      output: new ConsoleOutputHandler(),
484→      watcher: { addFile: (f) => newMultiWatcher.addFile(f) },
485→      session: new NoOpSessionHandler(),
486→      enabled: options.follow && options.withSubagents,
487→      onNewSubagent: openPaneForSubagent,
488→      onSubagentEnter: openPaneForSubagent,
489→      onSubagentDone,
490→      hasPane: hasPaneCallback,
491→    });
