587→/**
588→ * Claude Code Agent
589→ */
590→export class ClaudeAgent implements Agent {
591→  readonly type = 'claude' as const;
592→  readonly finder: SessionFinder;
593→  readonly parser: LineParser;
594→
595→  constructor(options: ParserOptions = { verbose: false }) {
596→    this.finder = new ClaudeSessionFinder();
597→    this.parser = new ClaudeLineParser(options);
598→  }
599→}
