import { stat } from 'node:fs/promises';
import { homedir } from 'node:os';
import { join } from 'node:path';
import { Glob } from 'bun';
import type { Agent, LineParser, SessionFinder } from '../agent.interface.ts';
import type {
  ClaudeSessionResult,
  ParsedLine,
  ParserOptions,
  SessionFile,
} from '../../core/types.ts';
import {
  contentToString,
  formatMultiline,
  truncateByLines,
} from '../../utils/text.ts';
import { formatToolUse, isSubagentTool } from '../../utils/format-tool.ts';

/**
 * Claude Code Session Finder
 * 目錄結構: ~/.claude/projects/{encoded-path}/{UUID}.jsonl
 */
class ClaudeSessionFinder implements SessionFinder {
  private baseDir: string;

  constructor() {
    this.baseDir = join(homedir(), '.claude', 'projects');
  }

  getBaseDir(): string {
    return this.baseDir;
  }

  async findLatest(options: { project?: string }): Promise<SessionFile | null> {
    const glob = new Glob('**/*.jsonl');
    const files: { path: string; mtime: Date }[] = [];

    for await (const file of glob.scan({ cwd: this.baseDir, absolute: true })) {
      const filename = file.split('/').pop() || '';

      // 排除 agent-* 開頭的檔案
      if (filename.startsWith('agent-')) continue;

      // 只匹配 UUID 格式的檔案名
      const uuidPattern =
        /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}\.jsonl$/i;
      if (!uuidPattern.test(filename)) continue;

      // 如果有 project filter，做模糊比對
      if (options.project) {
        const pattern = options.project.toLowerCase();
        // 對路徑做模糊比對（包含專案目錄名稱）
        if (!file.toLowerCase().includes(pattern)) continue;
      }

      try {
        const stats = await stat(file);
        files.push({ path: file, mtime: stats.mtime });
      } catch {
        // 忽略無法讀取的檔案
      }
    }

    if (files.length === 0) return null;

    // 按修改時間排序，取最新的
    files.sort((a, b) => b.mtime.getTime() - a.mtime.getTime());

    const latest = files[0];
    if (!latest) return null;

    return {
      path: latest.path,
      mtime: latest.mtime,
      agentType: 'claude',
    };
  }

  /**
   * 找到 subagent 檔案
   * 新結構: {sessionId}/subagents/agent-{7位hex}.jsonl
   * @param options.subagentId - 指定的 subagent ID，不提供則找最新的
   */
  async findSubagent(options: {
    project?: string;
    subagentId?: string;
  }): Promise<SessionFile | null> {
    const { project, subagentId } = options;

    // 決定 glob pattern（新結構：{UUID}/subagents/ 目錄下）
    const pattern = subagentId
      ? `**/*/subagents/agent-${subagentId}.jsonl`
      : '**/*/subagents/agent-*.jsonl';

    const glob = new Glob(pattern);
    const files: { path: string; mtime: Date }[] = [];

    for await (const file of glob.scan({ cwd: this.baseDir, absolute: true })) {
      const filename = file.split('/').pop() || '';

      // 驗證 subagent 檔名格式: agent-{7~40位十六進制}.jsonl
      const subagentPattern = /^agent-[0-9a-f]{7,40}\.jsonl$/i;
      if (!subagentPattern.test(filename)) continue;

      // project filter
      if (project && !file.toLowerCase().includes(project.toLowerCase())) {
        continue;
      }

      try {
        const stats = await stat(file);
        files.push({ path: file, mtime: stats.mtime });
      } catch {
        // 忽略無法讀取的檔案
      }
    }

    if (files.length === 0) return null;

    // 按修改時間排序，取最新的
    files.sort((a, b) => b.mtime.getTime() - a.mtime.getTime());
    const latest = files[0];
    if (!latest) return null;

    return {
      path: latest.path,
      mtime: latest.mtime,
      agentType: 'claude',
    };
  }

  /**
   * 依 session ID 查找 session 檔案
   * 支援主 session（UUID）和 subagent（7位hex）
   * 當指定 subagent ID 時，會同時返回主 session 和 subagent
   */
  async findBySessionId(
    sessionId: string,
    options: { project?: string }
  ): Promise<SessionFile | ClaudeSessionResult | null> {
    const idType = this.detectIdType(sessionId);

    // 如果是主 session UUID 或未知類型，先嘗試找主 session
    if (idType === 'main' || idType === 'unknown') {
      const mainResult = await this.findMainBySessionId(sessionId, options);
      if (mainResult) return mainResult;
    }

    // 如果是 subagent ID 或未知類型（且主 session 沒找到），嘗試找 subagent
    if (idType === 'subagent' || idType === 'unknown') {
      const subagentResult = await this.findSubagentBySessionId(
        sessionId,
        options
      );
      if (subagentResult) {
        // 反推主 session
        const mainPath = this.getMainSessionFromSubagent(subagentResult.path);
        if (mainPath) {
          try {
            const mainStats = await stat(mainPath);
            return {
              main: {
                path: mainPath,
                mtime: mainStats.mtime,
                agentType: 'claude',
              },
              subagent: subagentResult,
            };
          } catch {
            // 主 session 不存在，只返回 subagent
            return subagentResult;
          }
        }
        return subagentResult;
      }
    }

    return null;
  }

  /**
   * 判斷 ID 類型
   */
  private detectIdType(id: string): 'main' | 'subagent' | 'unknown' {
    // 完整 UUID 格式
    const uuidPattern =
      /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
    // Subagent 格式：agent-{7hex} 或純 {7hex}
    const subagentPattern = /^(agent-)?[0-9a-f]{7}$/i;

    if (uuidPattern.test(id)) return 'main';
    if (subagentPattern.test(id)) return 'subagent';

    // 如果是 UUID 前綴（8位以上但不完整），視為主 session
    if (/^[0-9a-f]{8,35}$/i.test(id)) return 'main';

    return 'unknown';
  }

  /**
   * 從 subagent 路徑反推主 session 路徑
   * 路徑結構: {projectDir}/{sessionUUID}/subagents/agent-xxx.jsonl
   */
  private getMainSessionFromSubagent(subagentPath: string): string | null {
    const parts = subagentPath.split('/');
    const subagentsIdx = parts.lastIndexOf('subagents');

    if (subagentsIdx === -1 || subagentsIdx < 2) return null;

    const sessionUUID = parts[subagentsIdx - 1];
    const projectDir = parts.slice(0, subagentsIdx - 1).join('/');

    // 主 session 在 projectDir 下，檔名為 sessionUUID.jsonl
    return join(projectDir, `${sessionUUID}.jsonl`);
  }

  /**
   * 依 session ID 查找主 session
   */
  private async findMainBySessionId(
    sessionId: string,
    options: { project?: string }
  ): Promise<SessionFile | null> {
    const glob = new Glob('**/*.jsonl');
    const candidates: { path: string; mtime: Date; priority: number }[] = [];

    const uuidPattern =
      /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}\.jsonl$/i;
    const searchTerm = sessionId.toLowerCase();

    for await (const file of glob.scan({ cwd: this.baseDir, absolute: true })) {
      const filename = file.split('/').pop() || '';

      // 排除 subagent 檔案
      if (filename.startsWith('agent-')) continue;

      // 只匹配 UUID 格式的檔案名
      if (!uuidPattern.test(filename)) continue;

      // project filter
      if (options.project) {
        const pattern = options.project.toLowerCase();
        if (!file.toLowerCase().includes(pattern)) continue;
      }

      const baseName = filename.replace(/\.jsonl$/, '').toLowerCase();

      // 計算匹配優先級
      let priority = 0;
      if (baseName === searchTerm) {
        priority = 3; // 精確匹配
      } else if (baseName.startsWith(searchTerm)) {
        priority = 2; // 前綴匹配
      } else if (baseName.includes(searchTerm)) {
        priority = 1; // 包含匹配
      }

      if (priority === 0) continue;

      try {
        const stats = await stat(file);
        candidates.push({ path: file, mtime: stats.mtime, priority });
      } catch {
        // 忽略
      }
    }

    if (candidates.length === 0) return null;

    // 排序：優先級降序 > mtime 降序
    candidates.sort((a, b) => {
      if (b.priority !== a.priority) return b.priority - a.priority;
      return b.mtime.getTime() - a.mtime.getTime();
    });

    const best = candidates[0];
    if (!best) return null;

    return {
      path: best.path,
      mtime: best.mtime,
      agentType: 'claude',
    };
  }

  /**
   * 依 session ID 查找 subagent
   */
  private async findSubagentBySessionId(
    sessionId: string,
    options: { project?: string }
  ): Promise<SessionFile | null> {
    // 正規化：移除 agent- 前綴
    const normalizedId = sessionId.replace(/^agent-/i, '').toLowerCase();

    const glob = new Glob('**/*/subagents/agent-*.jsonl');
    const candidates: { path: string; mtime: Date; priority: number }[] = [];

    const subagentPattern = /^agent-([0-9a-f]{7,40})\.jsonl$/i;

    for await (const file of glob.scan({ cwd: this.baseDir, absolute: true })) {
      const filename = file.split('/').pop() || '';
      const match = filename.match(subagentPattern);

      if (!match) continue;

      const subagentId = (match[1] || '').toLowerCase();

      // project filter
      if (options.project) {
        const pattern = options.project.toLowerCase();
        if (!file.toLowerCase().includes(pattern)) continue;
      }

      // 計算匹配優先級
      let priority = 0;
      if (subagentId === normalizedId) {
        priority = 3; // 精確匹配
      } else if (subagentId.startsWith(normalizedId)) {
        priority = 2; // 前綴匹配
      } else if (subagentId.includes(normalizedId)) {
        priority = 1; // 包含匹配
      }

      if (priority === 0) continue;

      try {
        const stats = await stat(file);
        candidates.push({ path: file, mtime: stats.mtime, priority });
      } catch {
        // 忽略
      }
    }

    if (candidates.length === 0) return null;

    // 排序：優先級降序 > mtime 降序
    candidates.sort((a, b) => {
      if (b.priority !== a.priority) return b.priority - a.priority;
      return b.mtime.getTime() - a.mtime.getTime();
    });

    const best = candidates[0];
    if (!best) return null;

    return {
      path: best.path,
      mtime: best.mtime,
      agentType: 'claude',
    };
  }
}

/**
 * Claude Code JSONL 解析器
 */
class ClaudeLineParser implements LineParser {
  private verbose: boolean;
  /** 追蹤 assistant message 內部的處理進度 */
  private currentMessageState: {
    data: Record<string, unknown>;
    contentParts: Array<{
      type: string;
      text?: string;
      name?: string;
      input?: Record<string, unknown>;
    }>;
    partIndex: number;
    modelShort: string;
    hasTextBefore: boolean;
  } | null = null;
  /** 追蹤已處理的 line，避免 while 迴圈重複處理 */
  private lastProcessedLine: string | null = null;

  constructor(options: ParserOptions = { verbose: false }) {
    this.verbose = options.verbose;
  }

  parse(line: string): ParsedLine | null {
    // 如果正在處理 assistant message 的內部狀態
    if (this.currentMessageState) {
      const result = this.processAssistantPart();
      if (result) return result;
      // 處理完畢，清除狀態並回傳 null
      this.currentMessageState = null;
      return null;
    }

    if (!line.trim()) return null;

    // 避免重複處理同一個 line（非 assistant message 不需要 while 迴圈）
    if (line === this.lastProcessedLine) {
      return null;
    }
    this.lastProcessedLine = line;

    try {
      const data = JSON.parse(line);
      const type = data.type || 'unknown';
      const timestamp = data.timestamp || '';

      // assistant message 需要特殊處理（可能包含多個 tool_use）
      if (type === 'assistant') {
        return this.parseAssistantMessage(data, timestamp);
      }

      // toolUseResult 記錄（subagent 完成時的回傳）
      if (data.toolUseResult) {
        return this.parseToolUseResult(data, timestamp);
      }

      const formatted = this.format(data);

      // 空內容不輸出
      if (!formatted) return null;

      return {
        type,
        timestamp,
        raw: data,
        formatted,
      };
    } catch {
      return null;
    }
  }

  /**
   * 解析 assistant message，拆分成多個部分
   */
  private parseAssistantMessage(
    data: Record<string, unknown>,
    _timestamp: string
  ): ParsedLine | null {
    const message = data.message as {
      model?: string;
      content: Array<{
        type: string;
        text?: string;
        name?: string;
        input?: Record<string, unknown>;
      }>;
    };
    const model = message?.model || '';
    const content = message?.content || [];

    // 簡化 model 顯示
    const modelShort = model
      .replace('claude-', '')
      .replace('-20251101', '')
      .replace('-', ' ');

    // 過濾有效的部分（text 或 tool_use）
    const validParts = content.filter(
      (part) =>
        (part.type === 'text' && part.text?.trim()) ||
        (part.type === 'tool_use' && part.name)
    );

    if (validParts.length === 0) return null;

    // 初始化狀態
    this.currentMessageState = {
      data,
      contentParts: validParts,
      partIndex: 0,
      modelShort,
      hasTextBefore: false,
    };

    return this.processAssistantPart();
  }

  /**
   * 處理 assistant message 的下一個部分
   */
  private processAssistantPart(): ParsedLine | null {
    if (!this.currentMessageState) return null;

    const { data, contentParts, partIndex, modelShort, hasTextBefore } =
      this.currentMessageState;
    if (partIndex >= contentParts.length) return null;

    const part = contentParts[partIndex];
    if (!part) return null;

    this.currentMessageState.partIndex++;
    const timestamp = (data as { timestamp?: string }).timestamp || '';

    if (part.type === 'text' && part.text) {
      this.currentMessageState.hasTextBefore = true;
      const preview = truncateByLines(part.text, { verbose: this.verbose });
      const modelInfo = modelShort && !hasTextBefore ? `(${modelShort})` : '';
      return {
        type: 'assistant',
        timestamp,
        raw: data,
        formatted: `${modelInfo}${formatMultiline(preview)}`,
      };
    }

    if (part.type === 'tool_use' && part.name) {
      const isTask = isSubagentTool(part.name);
      const taskDescription =
        isTask && typeof part.input?.description === 'string'
          ? part.input.description
          : undefined;

      return {
        type: 'function_call',
        timestamp,
        raw: part,
        formatted: formatToolUse(part.name, part.input, {
          verbose: this.verbose,
        }),
        toolName: part.name,
        isTaskToolUse: isTask,
        taskDescription,
      };
    }

    return null;
  }

  /**
   * 解析 toolUseResult 記錄（subagent 完成時的回傳）
   */
  private parseToolUseResult(
    data: Record<string, unknown>,
    timestamp: string
  ): ParsedLine | null {
    const toolUseResult = data.toolUseResult as {
      status?: string;
      agentId?: string;
      prompt?: string;
      totalDurationMs?: number;
      totalTokens?: number;
      totalToolUseCount?: number;
    };

    if (!toolUseResult) return null;

    const { status, agentId, totalDurationMs, totalTokens, totalToolUseCount } =
      toolUseResult;

    // 格式化輸出
    const parts: string[] = [];
    if (status) parts.push(status);
    if (agentId) parts.push(`agent:${agentId}`);
    if (totalDurationMs) parts.push(`${(totalDurationMs / 1000).toFixed(1)}s`);
    if (totalTokens) parts.push(`${totalTokens} tokens`);
    if (totalToolUseCount) parts.push(`${totalToolUseCount} tools`);

    const formatted = parts.length > 0 ? `(${parts.join(', ')})` : '';

    return {
      type: 'tool_result',
      timestamp,
      raw: data,
      formatted,
    };
  }

  private format(data: Record<string, unknown>): string {
    const type = data.type as string;

    switch (type) {
      case 'file-history-snapshot': {
        return ''; // 不顯示 snapshot
      }

      case 'user': {
        const message = data.message as { content: unknown };
        const content = contentToString(message?.content);
        const preview = truncateByLines(content, { verbose: this.verbose });
        return formatMultiline(preview);
      }

      // assistant 由 parseAssistantMessage 處理

      default:
        return '';
    }
  }
}

/**
 * Claude Code Agent
 */
export class ClaudeAgent implements Agent {
  readonly type = 'claude' as const;
  readonly finder: SessionFinder;
  readonly parser: LineParser;

  constructor(options: ParserOptions = { verbose: false }) {
    this.finder = new ClaudeSessionFinder();
    this.parser = new ClaudeLineParser(options);
  }
}

