 * DisplayController 選項
 */
export interface DisplayControllerOptions {
  /** 是否啟用持久狀態列（需要 TTY） */
  persistentStatusLine?: boolean;
  /** 歷史回看時顯示的最大行數 */
  historyLines?: number;
}

/**
 * ANSI Escape Codes
 */
