  2→
  3→/**
  4→ * Watcher session 資訊
  5→ */
  6→export interface WatcherSession {
  7→  id: string; // 識別碼（如 "main" 或 agentId）
  8→  label: string; // 顯示標籤（如 "[MAIN]" 或 "[a0627b6]"）
  9→  path: string; // 檔案路徑
 10→  buffer: string[]; // 輸出緩衝
 11→  isDone: boolean; // 是否已結束
 12→  createdAt: number; // 建立時間戳記（毫秒）
 13→}
 14→
 15→/**
 16→ * SessionManager 選項
 17→ */
 18→export interface SessionManagerOptions {
 19→  /** 每個 session 的緩衝大小限制（行數），預設 1000 */
 20→  bufferSize?: number;
 21→  /** active session 的輸出回調 */
 22→  onOutput: (content: string, session: WatcherSession) => void;
 23→  /** 新 session 加入時的回調 */
 24→  onSessionAdded?: (session: WatcherSession) => void;
 25→  /** session 切換時的回調 */
 26→  onSessionSwitched?: (
 27→    session: WatcherSession,
 28→    allSessions: WatcherSession[]
 29→  ) => void;
 30→}
 31→
 32→/**
 33→ * Session 管理器 - 管理多個 watcher session 的輸出切換
 34→ *
 35→ * 用於 interactive mode，讓使用者可以在主會話和 subagent 之間切換顯示。
 36→ * 專注於 session 狀態管理和輸出路由，不直接控制 file watching。
 37→ */
 38→export class SessionManager {
 39→  private sessions: WatcherSession[] = [];
 40→  private activeIndex: number = 0;
 41→  private bufferSize: number;
 42→  private options: SessionManagerOptions;
 43→
 44→  constructor(options: SessionManagerOptions) {
 45→    this.options = options;
 46→    this.bufferSize = options.bufferSize ?? 1000;
 47→  }
 48→
 49→  /**
 50→   * 新增 session
 51→   * - main session 永遠在 index 0
 52→   * - 其他 session 插入到 index 1（新的在左邊）
 53→   */
 54→  addSession(id: string, label: string, path: string): WatcherSession {
 55→    // 檢查是否已存在
 56→    const existing = this.sessions.find((s) => s.id === id);
 57→    if (existing) {
 58→      return existing;
 59→    }
 60→
 61→    const session: WatcherSession = {
 62→      id,
 63→      label,
 64→      path,
 65→      buffer: [],
 66→      isDone: false,
 67→      createdAt: Date.now(),
 68→    };
 69→
 70→    // 排序邏輯：
 71→    // - main session 永遠在 index 0
 72→    // - 其他 session 插入到 index 1（新的在左邊）
 73→    if (id === 'main') {
 74→      this.sessions.unshift(session); // main 放在最前面
 75→      // 插入到 0，所有元素往後移，activeIndex 要 +1
 76→      // 但如果是第一次新增 session，保持 activeIndex = 0
 77→      if (this.sessions.length > 1) {
 78→        this.activeIndex++;
 79→      }
 80→    } else {
 81→      // 找到 main session 的位置，插入其後
 82→      const insertIndex = this.sessions[0]?.id === 'main' ? 1 : 0;
 83→      this.sessions.splice(insertIndex, 0, session);
 84→      // 如果插入位置 <= activeIndex，activeIndex 要 +1 以保持使用者看到相同的 session
 85→      if (insertIndex <= this.activeIndex) {
 86→        this.activeIndex++;
 87→      }
 88→    }
 89→
 90→    this.options.onSessionAdded?.(session);
 91→
 92→    return session;
 93→  }
 94→
 95→  /**
 96→   * 取得所有 sessions
 97→   */
 98→  getAllSessions(): WatcherSession[] {
 99→    return [...this.sessions];
100→  }
101→
102→  /**
103→   * 取得目前 active 的 session
104→   */
105→  getActiveSession(): WatcherSession | null {
106→    return this.sessions[this.activeIndex] ?? null;
107→  }
108→
109→  /**
110→   * 取得 active index
111→   */
112→  getActiveIndex(): number {
113→    return this.activeIndex;
114→  }
115→
116→  /**
117→   * 切換到下一個 session
118→   */
119→  switchNext(): WatcherSession | null {
120→    if (this.sessions.length === 0) return null;
121→
122→    this.activeIndex = (this.activeIndex + 1) % this.sessions.length;
123→    const session = this.sessions[this.activeIndex] ?? null;
124→    if (session) {
125→      this.options.onSessionSwitched?.(session, this.sessions);
126→    }
127→
128→    return session;
129→  }
130→
131→  /**
132→   * 切換到上一個 session
133→   */
134→  switchPrev(): WatcherSession | null {
135→    if (this.sessions.length === 0) return null;
136→
137→    this.activeIndex =
138→      (this.activeIndex - 1 + this.sessions.length) % this.sessions.length;
139→    const session = this.sessions[this.activeIndex] ?? null;
140→    if (session) {
141→      this.options.onSessionSwitched?.(session, this.sessions);
142→    }
143→
144→    return session;
145→  }
146→
147→  /**
148→   * 切換到指定 session（by id）
149→   */
150→  switchTo(id: string): WatcherSession | null {
151→    const index = this.sessions.findIndex((s) => s.id === id);
152→    if (index === -1) return null;
153→
154→    this.activeIndex = index;
155→    const session = this.sessions[this.activeIndex] ?? null;
156→    if (session) {
157→      this.options.onSessionSwitched?.(session, this.sessions);
158→    }
159→
160→    return session;
161→  }
162→
163→  /**
164→   * 處理輸出
165→   * - active session: 直接輸出，同時存入 buffer（供切換後回看）
166→   * - 非 active session: 存入 buffer
167→   */
168→  handleOutput(label: string, content: string): void {
169→    const session = this.sessions.find((s) => s.label === label);
170→    if (!session) return;
171→
172→    const activeSession = this.getActiveSession();
173→
174→    // 所有 session 都存入 buffer（全量緩衝）
175→    session.buffer.push(content);
176→
177→    // 限制 buffer 大小
178→    if (session.buffer.length > this.bufferSize) {
179→      session.buffer.shift();
180→    }
181→
182→    // Active session 同時輸出到顯示
183→    if (session === activeSession) {
184→      this.options.onOutput(content, session);
185→    }
186→  }
187→
188→  /**
189→   * 取得 session 的緩衝內容（回傳 copy 以防止外部意外修改）
190→   */
191→  getSessionBuffer(id: string): string[] {
192→    const session = this.sessions.find((s) => s.id === id);
193→    return session?.buffer.slice() ?? [];
194→  }
195→
196→  /**
197→   * 清空 session 的緩衝
198→   */
199→  clearSessionBuffer(id: string): void {
200→    const session = this.sessions.find((s) => s.id === id);
201→    if (session) {
202→      session.buffer = [];
203→    }
204→  }
205→
206→  /**
207→   * 標記 session 為已結束
208→   */
209→  markSessionDone(id: string): void {
210→    const session = this.sessions.find((s) => s.id === id);
211→    if (session) {
212→      session.isDone = true;
213→    }
214→  }
215→
216→  /**
217→   * 輸出當前 active session 的緩衝內容（切換後顯示歷史）
218→   */
219→  flushActiveBuffer(): void {
220→    const session = this.getActiveSession();
221→    if (!session || session.buffer.length === 0) return;
222→
223→    for (const content of session.buffer) {
224→      this.options.onOutput(content, session);
225→    }
226→
227→    session.buffer = [];
228→  }
229→
230→  /**
231→   * 建立 WatchedFile 列表給 MultiFileWatcher 使用
232→   */
233→  getWatchedFiles(): WatchedFile[] {
234→    return this.sessions.map((s) => ({
235→      path: s.path,
236→      label: s.label,
237→    }));
238→  }
239→
240→  /**
241→   * Session 總數
242→   */
243→  get sessionCount(): number {
244→    return this.sessions.length;
245→  }
246→
247→  /**
248→   * 是否只有一個 session（無需切換）
249→   */
250→  get isSingleSession(): boolean {
251→    return this.sessions.length <= 1;
252→  }
253→}
