257→  /**
258→   * 顯示切換訊息和歷史內容
259→   */
260→  showSwitchMessage(session: WatcherSession, historyContent: string[]): void {
261→    // 顯示分隔線（包含完成狀態）
262→    const doneStatus = session.isDone ? chalk.green(' ✓ (completed)') : '';
263→    const separator =
264→      chalk.gray(`\n─── Switched to ${session.label}`) +
265→      doneStatus +
266→      chalk.gray(` ───`);
267→    this.write(separator);
268→
269→    // 顯示歷史內容（最近 N 行）
270→    const linesToShow = historyContent.slice(-this.historyLines);
271→    if (linesToShow.length > 0) {
272→      const historyHeader = chalk.gray(
273→        `[Showing ${linesToShow.length} buffered lines]`
274→      );
275→      this.write(historyHeader);
276→      for (const line of linesToShow) {
277→        this.write(line);
278→      }
279→      const historyFooter = chalk.gray(`[End of buffer]`);
280→      this.write(historyFooter);
281→    } else {
282→      // Buffer 是空的，顯示提示訊息
283→      if (session.isDone) {
284→        this.write(chalk.gray(`[No new content - session completed]`));
285→      } else {
286→        this.write(
287→          chalk.gray(`[No buffered content - waiting for new output...]`)
288→        );
289→      }
290→    }
291→  }
292→
293→  /**
294→   * 截斷字串至指定寬度（考慮 ANSI codes）
295→   */
296→  private truncateToWidth(str: string, maxWidth: number): string {
297→    // 移除 ANSI codes 計算實際長度
298→    // eslint-disable-next-line no-control-regex
299→    const plainStr = str.replace(/\x1b\[[0-9;]*m/g, '');
300→    if (plainStr.length <= maxWidth) {
301→      return str;
302→    }
303→
304→    // 簡單截斷（不完美但足夠用）
305→    let visibleLength = 0;
306→    let result = '';
307→    let inEscape = false;
308→
309→    for (const char of str) {
310→      if (char === '\x1b') {
311→        inEscape = true;
312→        result += char;
313→      } else if (inEscape) {
314→        result += char;
315→        if (char === 'm') {
316→          inEscape = false;
317→        }
318→      } else {
319→        if (visibleLength >= maxWidth - 3) {
320→          result += '...';
321→          break;
322→        }
323→        result += char;
324→        visibleLength++;
325→      }
326→    }
327→
328→    return result;
329→  }
330→
331→  /**
332→   * 是否支援持久狀態列
333→   */
334→  get supportsPersistentStatusLine(): boolean {
335→    return process.stdout.isTTY === true;
336→  }
337→}
