182→/**
183→ * createSuperFollowController 的配置
184→ */
185→export interface SuperFollowControllerConfig {
186→  projectDir: string;
187→  getCurrentPath: () => string;
188→  onSwitch: (nextFile: SessionFile) => Promise<void>;
189→  autoSwitch: boolean;
190→  /** 注入的 session 搜尋函數（用於尋找專案中最新的 session） */
191→  findLatestInProject: (projectDir: string) => Promise<SessionFile | null>;
192→}
193→
194→/**
195→ * 建立 super-follow 控制器（自動切換到最新 session）
196→ */
197→export function createSuperFollowController(
198→  config: SuperFollowControllerConfig
199→): {
200→  start: () => void;
201→  stop: () => void;
202→} {
203→  let stopped = false;
204→  let pendingSwitchPath: string | null = null;
205→  let pendingSwitchTimer: ReturnType<typeof setTimeout> | null = null;
206→  let pollTimer: ReturnType<typeof setTimeout> | null = null;
207→
208→  const clearPendingSwitch = (): void => {
209→    if (pendingSwitchTimer) {
210→      clearTimeout(pendingSwitchTimer);
211→      pendingSwitchTimer = null;
212→    }
213→    pendingSwitchPath = null;
214→  };
215→
216→  const scheduleSwitch = (nextPath: string): void => {
217→    if (pendingSwitchPath === nextPath) return;
218→    pendingSwitchPath = nextPath;
219→    if (pendingSwitchTimer) clearTimeout(pendingSwitchTimer);
220→
221→    pendingSwitchTimer = setTimeout(async () => {
222→      if (stopped || !pendingSwitchPath) return;
223→      try {
224→        const latest = await config.findLatestInProject(config.projectDir);
225→        if (
226→          latest &&
227→          latest.path === pendingSwitchPath &&
228→          latest.path !== config.getCurrentPath()
229→        ) {
230→          await config.onSwitch(latest);
231→        }
232→      } catch {
233→        // ignore
234→      } finally {
235→        clearPendingSwitch();
236→      }
237→    }, SUPER_FOLLOW_DELAY_MS);
238→  };
239→
240→  const start = (): void => {
241→    if (!config.autoSwitch) return;
242→
243→    const poll = async (): Promise<void> => {
244→      if (stopped) return;
245→      try {
246→        const latest = await config.findLatestInProject(config.projectDir);
247→        if (latest && latest.path !== config.getCurrentPath()) {
248→          scheduleSwitch(latest.path);
249→        } else if (!latest) {
250→          clearPendingSwitch();
251→        }
252→      } catch {
253→        // ignore
254→      } finally {
255→        pollTimer = setTimeout(poll, SUPER_FOLLOW_POLL_MS);
256→      }
257→    };
258→
259→    poll();
260→  };
261→
262→  const stop = (): void => {
263→    stopped = true;
264→    clearPendingSwitch();
265→    if (pollTimer) {
266→      clearTimeout(pollTimer);
267→      pollTimer = null;
268→    }
269→  };
270→
271→  return { start, stop };
272→}
