 92→ * createOnLineHandler 的配置
 93→ */
 94→export interface OnLineHandlerConfig {
 95→  parsers: Map<string, LineParser>;
 96→  formatter: Formatter;
 97→  detector: SubagentDetector;
 98→  onOutput: (formatted: string, label: string) => void;
 99→  verbose: boolean;
100→  /** 過濾函數：回傳 true 表示應該輸出，false 表示跳過（Phase 2.3） */
101→  shouldOutput?: (label: string) => boolean;
102→}
103→
104→/**
105→ * 建立標準 onLine handler，供 MultiFileWatcher 的 onLine callback 使用
106→ */
107→export function createOnLineHandler(
108→  config: OnLineHandlerConfig
109→): (line: string, label: string) => void {
110→  return (line: string, label: string) => {
111→    // agent_progress：subagent 進入或 resume，每次進入都觸發 pane 開啟
112→    // 前置字串檢查避免每行都 JSON.parse（熱路徑優化）
113→    if (label === MAIN_LABEL && line.includes('"agent_progress"')) {
114→      try {
115→        const data = JSON.parse(line) as {
116→          type?: string;
117→          data?: { type?: string; agentId?: string };
118→        };
119→        if (
120→          data.type === 'progress' &&
121→          data.data?.type === 'agent_progress' &&
122→          data.data?.agentId
123→        ) {
124→          config.detector.handleAgentProgress(data.data.agentId);
125→        }
126→      } catch {
127→        // 非 JSON 或無關格式，略過
128→      }
129→    }
130→
131→    let parser = config.parsers.get(label);
132→    if (!parser) {
133→      const newAgent = new ClaudeAgent({ verbose: config.verbose });
134→      parser = newAgent.parser;
135→      config.parsers.set(label, parser);
136→    }
137→
138→    let parsed = parser.parse(line);
139→    while (parsed) {
140→      parsed.sourceLabel = label;
141→
142→      // Phase 2.3: 過濾已有 pane 的 subagent 輸出
143→      if (config.shouldOutput && !config.shouldOutput(label)) {
144→        parsed = parser.parse(line);
145→        continue;
146→      }
147→
148→      config.onOutput(config.formatter.format(parsed), label);
149→
150→      // 早期 Subagent 偵測：當偵測到 Task tool_use 時立即掃描
151→      if (label === MAIN_LABEL && parsed.isTaskToolUse) {
152→        // Push description before early detection so it's queued when scan triggers
153→        if (parsed.taskDescription) {
154→          config.detector.pushDescription(parsed.taskDescription);
155→        }
156→        config.detector.handleEarlyDetection();
157→      }
158→
159→      // 備援機制：從主 session 的 toolUseResult 檢查新 subagent
160→      if (label === MAIN_LABEL) {
161→        const raw = parsed.raw as {
162→          toolUseResult?: {
163→            agentId?: string;
164→            commandName?: string;
165→            status?: string;
166→          };
167→        };
168→        const agentId = raw?.toolUseResult?.agentId;
169→        const commandName = raw?.toolUseResult?.commandName;
170→        const status = raw?.toolUseResult?.status;
171→
172→        if (agentId && !commandName && status !== 'forked') {
173→          config.detector.handleFallbackDetection(agentId);
174→        }
175→      }
176→
177→      parsed = parser.parse(line);
178→    }
179→  };
180→}
181→
182→/**
183→ * createSuperFollowController 的配置
184→ */
185→export interface SuperFollowControllerConfig {
186→  projectDir: string;
187→  getCurrentPath: () => string;
188→  onSwitch: (nextFile: SessionFile) => Promise<void>;
189→  autoSwitch: boolean;
190→  /** 注入的 session 搜尋函數（用於尋找專案中最新的 session） */
191→  findLatestInProject: (projectDir: string) => Promise<SessionFile | null>;

