import { PaneManager } from './terminal/pane-manager.ts';

/**
 * 條件式日誌輸出 - 在 quiet 模式下抑制非錯誤訊息
 */
function log(quiet: boolean, ...args: unknown[]): void {
  if (!quiet) {
    console.log(...args);
  }
}

async function main(): Promise<void> {
  const options = parseArgs(process.argv);

  // 選擇 Agent
  const agent: Agent =
